<script setup lang="ts">
import { useI18n } from "vue-i18n"
import { EMAIL_VERIFICATION } from "@/constants"
import { goPage } from "@/modules/utils/util"
import { ref, watch, onMounted, onUnmounted } from "vue"
import { AxiosError } from "axios"
import useStore from "@/stores"

const { t } = useI18n()

const store = useStore()

const email = store.findId.email

const showTooltip = ref(false)
const showModal = ref(false)

const openModal = () => {
  showModal.value = true
}

const closeModal = () => {
  showModal.value = false
}

const verificationCode = ref("")
const verificationCodeError = ref("")
const verificationCodeInput = ref<HTMLInputElement | null>(null)
const processing = ref(false)

const errorCodeMap: Record<string, string> = {
  ERR_EMAIL_CODE_NOT_FOUND: "auth.error.verificationCode.notFound",
  ERR_EMAIL_VERIFY_ALREADY_COMPLETED: "auth.error.verificationCode.alreadyVerified",
  ERR_EMAIL_CODE_EXPIRED: "auth.error.verificationCode.expired",
  ERR_EMAIL_CODE_LOCKED: "auth.error.verificationCode.locked",
  ERR_EMAIL_CODE_FAIL_LIMIT_EXCEEDED: "auth.error.verificationCode.failLimitExceeded",
  ERR_EMAIL_CODE_INVALID: "auth.error.verificationCode.invalid",
}

const resendCountdown = ref(EMAIL_VERIFICATION.RESEND_COOLDOWN_SECONDS)
let resendTimer: ReturnType<typeof setInterval> | null = null

const startResendTimer = () => {
  resendCountdown.value = EMAIL_VERIFICATION.RESEND_COOLDOWN_SECONDS
  if (resendTimer) clearInterval(resendTimer)
  resendTimer = setInterval(() => {
    resendCountdown.value--
    if (resendCountdown.value <= 0) {
      clearInterval(resendTimer!)
      resendTimer = null
    }
  }, 1000)
}

const resendVerificationCode = async () => {
  await store.findId.emailVerificationRequest()
  startResendTimer()
}

const validateVerificationCode = () => {
  verificationCodeError.value = ""

  if (!verificationCode.value) {
    return verificationCodeError.value = "auth.error.verificationCode.required"
  }

  if (verificationCode.value.length !== EMAIL_VERIFICATION.CODE_LENGTH) {
    return verificationCodeError.value = "auth.error.verificationCode.invalid"
  }
}

const clearVerificationCodeError = () => {
  verificationCodeError.value = ""
}

watch(verificationCode, (code) => {
  if (code.length === EMAIL_VERIFICATION.CODE_LENGTH) {
    goNextStep()
  }
})

const goNextStep = async () => {
  validateVerificationCode()

  if (verificationCodeError.value) return

  processing.value = true

  const [validateRes] = await Promise.all([
    store.findId.emailVerificationValidate(verificationCode.value),
    new Promise(resolve => setTimeout(resolve, 800))
  ])

  if (!validateRes.success) {
    if (validateRes.error instanceof AxiosError) {
      const resultCode = validateRes.error.response?.data?.code as string
      verificationCodeError.value = errorCodeMap[resultCode] ?? "auth.error.verificationCode.invalid"
    }
    processing.value = false
    return
  }

  const findRes = await store.findId.findUserId()

  if (findRes.success) {
    goPage("FindIdResult")
  } else {
    if (findRes.error instanceof AxiosError) {
      verificationCodeError.value = "auth.error.findId.failed"
    }
  }

  processing.value = false
}

onMounted(() => {
  verificationCodeInput.value?.focus()
  startResendTimer()
})

onUnmounted(() => {
  if (resendTimer) clearInterval(resendTimer)
})
</script>

